// Strip HTML tags, condense whitespace, limit to 8000 chars
const raw = $input.first().json.data || '';
const url = $('Webhook: Evaluate Job').first().json.body?.url || $('Webhook: Evaluate Job').first().json.url || '';

const text = raw
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ').trim()
  .slice(0, 8000);

return [{ json: { url, jd_text: text, char_count: text.length } }];

