// Parse OpenRouter response, extract eval JSON
const resp = $input.first().json;
const content = resp.choices?.[0]?.message?.content || '{}';

let eval_data;
try { eval_data = JSON.parse(content); }
catch { eval_data = { score: 0, error: 'parse failed', raw: content.slice(0, 500) }; }

const score = parseFloat(eval_data.score) || 0;

return [{ json: {
  ...eval_data,
  score,
  verdict: eval_data.verdict || (score >= 3.8 ? 'GO' : score >= 3.0 ? 'REVIEW' : 'SKIP'),
  eval_date: new Date().toISOString().split('T')[0],
  model_used: resp.model || 'unknown',
} }];
